#!/usr/bin/env node
// Excel/ODS ingestion tests: workbook -> deterministic CSV text -> CsvParser.
// Fixtures are generated by scripts/make-excel-fixtures.mjs (re-run on demand).
import { existsSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import * as XLSX from 'xlsx';
import CsvParser from '../src/parsers/csv-parser.js';
import {
    csvTextToBuffer,
    listSheets,
    nonEmptySheetNames,
    readWorkbook,
    sheetToCsvText,
} from '../src/parsers/excel-workbook.js';
import { makeExcelFixtures } from './make-excel-fixtures.mjs';

const FIXTURE_DIR = 'test-files/excel';
const parser = new CsvParser();
let failures = 0;

function assert(condition, message) {
    if (condition) return;
    failures++;
    console.error('FAIL:', message);
}

function loadWorkbook(filename) {
    const bytes = readFileSync(join(FIXTURE_DIR, filename));
    return readWorkbook(XLSX, bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength));
}

async function parseSheet(filename, sheetName = null) {
    const workbook = loadWorkbook(filename);
    const name = sheetName || nonEmptySheetNames(workbook)[0];
    const text = sheetToCsvText(workbook, name);
    const data = await parser.parse(csvTextToBuffer(text));
    return { workbook, text, data };
}

function assertDatetimeTable(label, data, expectedRows, expectedVars) {
    assert(data.metadata.numTimesteps === expectedRows, `${label}: expected ${expectedRows} rows, got ${data.metadata.numTimesteps}`);
    assert(data.metadata.timeKind === 'datetime', `${label}: expected datetime axis, got ${data.metadata.timeKind}`);
    for (const varName of expectedVars) {
        assert(!!data.variables[varName], `${label}: missing variable "${varName}" (has: ${Object.keys(data.variables).join(', ')})`);
    }
    const time = data.variables[data.metadata.timeName];
    for (let i = 1; i < time.data.length; i++) {
        assert(time.data[i] > time.data[i - 1], `${label}: time axis not strictly increasing at ${i}`);
    }
}

async function run() {
    if (!existsSync(join(FIXTURE_DIR, 'basic-datetime.xlsx'))) {
        console.log('fixtures missing; generating...');
        makeExcelFixtures();
    }

    for (const filename of ['basic-datetime.xlsx', 'basic-datetime.ods', 'basic-datetime.xls']) {
        const { data } = await parseSheet(filename);
        // CsvParser extracts inline "(V)" units, so variables lose the suffix.
        assertDatetimeTable(filename, data, 24, ['Voltage', 'Current', 'Status']);
        assert(data.variables['Voltage'].dataType !== 'string', `${filename}: Voltage should be numeric`);
        assert(data.variables['Status'].dataType === 'string', `${filename}: Status should stay a string column`);
    }

    {
        const workbook = loadWorkbook('multi-sheet.xlsx');
        const sheets = listSheets(workbook);
        assert(sheets.length === 4, `multi-sheet: expected 4 sheets, got ${sheets.length}`);
        assert(sheets.find(s => s.name === 'Empty')?.empty === true, 'multi-sheet: "Empty" should be empty');
        assert(sheets.find(s => s.name === 'HiddenSheet')?.hidden === true, 'multi-sheet: "HiddenSheet" should be hidden');
        assert(nonEmptySheetNames(workbook).join(',') === 'Measurements,Summary,HiddenSheet', 'multi-sheet: non-empty sheet list mismatch');
        const { data } = await parseSheet('multi-sheet.xlsx', 'Measurements');
        assertDatetimeTable('multi-sheet/Measurements', data, 24, ['Voltage']);
        const summary = await parseSheet('multi-sheet.xlsx', 'Summary');
        assert(summary.data.metadata.numTimesteps === 5, `multi-sheet/Summary: expected 5 rows, got ${summary.data.metadata.numTimesteps}`);
    }

    {
        const { data } = await parseSheet('header-units-preamble.xlsx');
        assertDatetimeTable('header-units-preamble', data, 12, ['Voltage', 'Current']);
        const voltage = data.variables['Voltage'];
        assert(voltage.data[0] === 230, `header-units-preamble: first Voltage should be 230, got ${voltage.data[0]}`);
    }

    {
        const { text, data } = await parseSheet('split-date-time.xlsx');
        assert(/^\d{4}-\d{2}-\d{2},08:00:00,40$/m.test(text), `split-date-time: expected time-only second column, got "${text.slice(0, 80)}..."`);
        assertDatetimeTable('split-date-time', data, 18, ['Power']);
    }

    {
        const workbook = loadWorkbook('mixed-content.xlsx');
        const text = sheetToCsvText(workbook, 'Mixed');
        assert(text.includes('"Smith, John","He said ""hi""",1,1.5'), `mixed-content: bad quoting: ${text}`);
        assert(text.includes('"Line\nbreak"'), 'mixed-content: embedded newline should stay quoted');
        assert(/café,0,42\b/.test(text), `mixed-content: formula cell should emit cached value 42: ${text}`);
        assert(/^plain,ok,1,$/m.test(text), `mixed-content: error cell should serialize empty: ${text}`);
    }

    {
        const { data } = await parseSheet('no-header-datetime.xlsx');
        assert(data.metadata.numTimesteps === 30, `no-header-datetime: expected 30 rows, got ${data.metadata.numTimesteps}`);
        assert(data.metadata.timeKind === 'datetime', `no-header-datetime: expected datetime axis, got ${data.metadata.timeKind}`);
        assert(data.metadata.hasHeader === false, 'no-header-datetime: should detect no header row');
    }

    for (const filename of ['no-header-numeric.xlsx', 'no-header-numeric.ods']) {
        const { data } = await parseSheet(filename);
        assert(data.metadata.numTimesteps === 40, `${filename}: expected 40 rows, got ${data.metadata.numTimesteps}`);
        assert(data.metadata.hasHeader === false, `${filename}: should detect no header row`);
    }

    {
        const { data } = await parseSheet('excel-serial-dates.xlsx');
        assert(data.metadata.numTimesteps === 48, `excel-serial-dates: expected 48 rows, got ${data.metadata.numTimesteps}`);
        assert(data.metadata.timeKind === 'datetime', `excel-serial-dates: serial numbers should map to a datetime axis, got ${data.metadata.timeKind}`);
        const originYear = new Date(data.metadata.timeOriginMs).getUTCFullYear();
        assert(originYear === 2024, `excel-serial-dates: origin should land in 2024, got ${originYear}`);
    }

    {
        const { data } = await parseSheet('microgrid-demo.xlsx');
        assertDatetimeTable('microgrid-demo', data, 192, ['P_carga', 'P_solar', 'SOC']);
    }

    {
        const { data } = await parseSheet('dates-1904.xlsx');
        assertDatetimeTable('dates-1904', data, 24, ['Voltage']);
        const originMs = data.metadata.timeOriginMs;
        const expected = new Date('2024-01-01T00:00:00').getTime();
        const dayMs = 86400_000;
        assert(Math.abs(originMs - expected) < dayMs, `dates-1904: origin should be ~2024-01-01, got ${new Date(originMs).toISOString()}`);
    }

    if (failures) {
        console.error(`\n${failures} failure(s)`);
        process.exit(1);
    }
    console.log('All Excel parser tests passed.');
}

run().catch(err => {
    console.error(err);
    process.exit(1);
});
